const res = await fetch("https://idx.quantyralabs.cc/api/v1/properties?dataset=stellar", {
  method: "POST",
  headers: {
    "Authorization": "Bearer ${process.env.IDX_API_TOKEN}",
    "Content-Type": "application/json",
    "X-Domain-Slug": "${process.env.IDX_DOMAIN_SLUG}"
  },
  body: JSON.stringify({ "city": "Largo", "limit": 2 }),
});
if (!res.ok) throw new Error(`API ${res.status}`);
const data = await res.json();
